SELECT es.id, es.engineer_id, es.task_id, es.start_time, es.end_time,
       es.schedule_type, es.remark, es.create_time,
       e.name AS engineer_name,
       pt.task_name AS task_name,
       pt.project_id AS project_id,
       p.project_name AS project_name
FROM engineer_schedule es
LEFT JOIN engineer e ON e.id = es.engineer_id AND e.deleted = 0
LEFT JOIN project_task pt ON pt.id = es.task_id AND pt.deleted = 0
LEFT JOIN project p ON p.id = pt.project_id AND p.deleted = 0

    es.deleted = 0

        AND es.engineer_id = #{query.engineerId}


        AND es.task_id = #{query.taskId}


        AND es.schedule_type = #{query.scheduleType}


        AND es.end_time >= #{query.startTime}


        AND es.start_time <= #{query.endTime}


        AND e.region = #{query.region}


ORDER BY es.start_time DESC

